example.code:
{
  "spec_id": "spec-autonomous-codefixer-v1",
  "agent_name": "codefixer",
  "pattern": "reflexion",
  "subagent_roles": {
    "executor": {"model": "claude-sonnet-4", "role": "edit code and run tests"},
    "critic": {"model": "claude-haiku-4", "role": "judge if tests pass and improvements possible"}
  },
  "caps": {"max_iterations": 8, "max_attempts": 3},
  "terminal_condition": "pytest tests/ exits 0 AND coverage >= baseline",
  "idempotency_class_per_tool": {
    "read_file": "idempotent",
    "edit_file": "dedup-keyed",
    "run_pytest": "idempotent",
    "git_commit": "non-idempotent"
  },
  "sandbox_required": true,
  "human_checkpoint_per_action": {
    "read_file": "not-required",
    "edit_file": "not-required",
    "run_pytest": "not-required",
    "git_commit": "required"
  },
  "owner": "alex@faion.net",
  "version": "1.0.0",
  "produced_at": "2026-05-22T20:00:00Z"
}
